it('should process order:status-changed event through the full pipeline', async () => {
  // Note: handleOrderStatusChanged uses event.order.userId as recipient.
  // Since OrderStatusChangedEvent doesn't carry user email, the recipient
  // is a userId string which fails email adapter validation → status 'failed'.
  await eventBus.emit(makeOrderStatusChangedEvent());

  const notifications = notificationService.getNotifications();
  expect(notifications).toHaveLength(1);
  expect(notifications[0]?.type).toBe('order_status_update');
  expect(notifications[0]?.body).toContain('pending');
  expect(notifications[0]?.body).toContain('confirmed');
  // Recipient is userId, not a valid email — adapter returns failure
  expect(notifications[0]?.status).toBe('failed');

  // Email adapter rejected the invalid recipient, so no email was recorded
  expect(emailAdapter.getSentEmails()).toHaveLength(0);

  // History still records the failed notification
  const logs = historyService.getByType('order_status_update');
  expect(logs).toHaveLength(1);
  expect(logs[0]?.status).toBe('failed');
});

